 1	import * as React from 'react';
 2	import Helmet from 'react-helmet';
 3	import { useTranslation } from 'react-i18next';
 4	import { Page, PageSection, Title } from '@patternfly/react-core';
 5	import { useLocation } from 'react-router-dom';
 6	import './kuadrant.css';
 7	import AssociatedResourceList from './AssociatedResourceList';
 8	import {
 9	  useK8sWatchResources,
10	  K8sResourceCommon,
11	  useActiveNamespace,
12	} from '@openshift-console/dynamic-plugin-sdk';
13	
14	import extractResourceNameFromURL from '../utils/nameFromPath';
15	
16	const HTTPRoutePoliciesPage: React.FC = () => {
17	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
18	  const [activeNamespace] = useActiveNamespace();
19	  const location = useLocation();
20	
21	  const routeName = extractResourceNameFromURL(location.pathname);
22	
23	  const resources = {
24	    httpRoute: {
25	      groupVersionKind: {
26	        group: 'gateway.networking.k8s.io',
27	        version: 'v1',
28	        kind: 'HTTPRoute',
29	      },
30	      namespace: activeNamespace,
31	      name: routeName,
32	      isList: false,
33	    },
34	  };
35	
36	  const watchedResources = useK8sWatchResources<{ httpRoute: K8sResourceCommon }>(resources);
37	  const { loaded, loadError, data: httpRoute } = watchedResources.httpRoute;
38	
39	  return (
40	    <>
41	      <Helmet>
42	        <title data-test="example-page-title">{t('Kuadrant Policies')}</title>
43	      </Helmet>
44	      <Page>
45	        <PageSection variant="light">
46	          <Title headingLevel="h2">{t('Kuadrant Policies')}</Title>
47	          {!loaded ? (
48	            <div>Loading...</div>
49	          ) : loadError ? (
50	            <div>Error loading HTTPRoute: {loadError.message}</div>
51	          ) : (
52	            <AssociatedResourceList resource={httpRoute} />
53	          )}
54	        </PageSection>
55	      </Page>
56	    </>
57	  );
58	};
59	
60	export default HTTPRoutePoliciesPage;

